scwin.newinput = async function () {
  $c.gus.cfEnableObjects($p, [vehclNo]);
  ds_vlAccount.removeAll();
  ds_vlFixCost.removeAll();
  ds_vlInsurance.removeAll();
  await scwin.f_defaultBlkCntrCls();
  if (ds_vehcl.getRowCount() == 0) {
    ds_vehcl.insertRow();
    autoVehcl.setValue("1");
    txt_steelVehclYn.setValue("0");
    chk_24VehclYn.setValue("1");
    scwin.oriCarTon = "";
  } else {
    let chk = 0;
    for (let i = 0; i < ds_vehcl.getRowCount(); i++) {
      if (ds_vehcl.getRowStatus(i) == "C") {
        chk++;
      }
    }
    if (chk > 0) {
      await $c.win.alert($p, "새로운 차량정보는 하나만 입력하실수 있습니다. 저장 후 다시 추가해주세요.");
      $c.gus.cfEnableObjects($p, [vehclNo]);
    } else {
      ds_vehcl.insertRow();
      let row = ds_vehcl.getRowPosition();
      ds_vehcl.setCellData(row, "ez110Idx", "");
      autoVehcl.setValue("1");
      txt_steelVehclYn.setValue("0");
      chk_24VehclYn.setValue("1");
    }
  }
  if (ds_temp.getRowCount() > 0) {
    let row = ds_vehcl.getRowPosition();
    ds_vehcl.setCellData(row, "blkCntrCls", ds_temp.getCellData(0, "code"));
  }
};
