scwin.saveVlFixCost = async function () {
  let fRow = ds_vlFixCost.getRowPosition();
  let levyStDdVal = ds_vlFixCost.getCellData(fRow, "levyStDd");
  let levyEndDdVal = ds_vlFixCost.getCellData(fRow, "levyEndDd");
  let levyAmtVal = ds_vlFixCost.getCellData(fRow, "levyAmt");
  let divsAmtVal = ds_vlFixCost.getCellData(fRow, "divsAmt");
  let divsYnVal = ds_vlFixCost.getCellData(fRow, "divsYn");
  if (levyStDdVal > levyEndDdVal) {
    await $c.win.alert($p, "부과시작일이 부과종료일보다 큽니다.");
    return;
  }
  if ((divsYnVal == "1" || divsYnVal == true) && levyStDdVal.substring(0, 6) == levyEndDdVal.substring(0, 6)) {
    await $c.win.alert($p, "부과 시작월과 부과 종료월이 같습니다.");
    return;
  }
  if (Number(levyAmtVal) < Number(divsAmtVal)) {
    await $c.win.alert($p, "분할 금액이 부과금액보다 큽니다.");
    return;
  }
  if (ds_vlFixCost.getRowCount() > 0) {
    if (ds_vlFixCost.getCellData(fRow, "vehclFcostAcnt") == "") {
      await $c.win.alert($p, "차량고정비를 선택해주세요");
      return false;
    }
    if (ds_vlFixCost.getCellData(fRow, "uncollNypay") == "") {
      await $c.win.alert($p, "부과기준을 선택해주세요");
      return false;
    }
    if (ds_vlFixCost.getCellData(fRow, "levyStDd") == "") {
      await $c.win.alert($p, "부과시작일 입력해주세요");
      return false;
    }
    if (ds_vlFixCost.getCellData(fRow, "levyEndDd") == "") {
      await $c.win.alert($p, "부과종료일 입력해주세요");
      return false;
    }
    if (ds_vlFixCost.getCellData(fRow, "levyDd") == "") {
      await $c.win.alert($p, "부과료일 입력해주세요");
      return false;
    }
    if (ds_vlFixCost.getCellData(fRow, "levyAmt") == "") {
      await $c.win.alert($p, "부과금을 입력해주세요");
      return false;
    }
    await $c.sbm.execute($p, sbm_vlFixCost);
  } else {
    await $c.win.alert($p, "신규버튼을 클릭하신 후 데이터를 입력해주세요");
  }
};
