scwin.deletethis = async function () {
  if (ds_vehcl.getRowCount() == 0) {
    await $c.win.alert($p, "데이터가 존재하지 않습니다.");
    return false;
  }
  let chk = await $c.win.confirm($p, "삭제하시겠습니까?");
  if (chk) {
    let row = ds_vehcl.getRowPosition();
    if (ds_vehcl.getRowStatus(row) == "C") {
      ds_vehcl.removeRow(row);
    } else {
      ds_del.removeAll();
      ds_del.insertRow();
      let delRow = ds_del.getRowPosition();
      let cond1Val = "" + ds_vehcl.getCellData(row, "ez110Idx");
      ds_del.setCellData(delRow, "cond1", cond1Val);
      ds_del.setCellData(delRow, "ez108Idx", "" + ds_vehcl.getCellData(row, "ez108Idx"));
      ds_del.setCellData(delRow, "vehclNo", "" + ds_vehcl.getCellData(row, "vehclNo"));
      ds_del.setCellData(delRow, "hdoIdx", "" + ds_vehcl.getCellData(row, "hdoIdx"));
      await $c.sbm.execute($p, sbm_del);
    }
    $c.gus.cfDisableObjects($p, [vehclNo]);
  }
};
