scwin.calcDivsFix = function () {
  let fRow = ds_vlFixCost.getRowPosition();
  let divsYnChecked = ds_vlFixCost.getCellData(fRow, "divsYn");
  if (divsYnChecked == "1" || divsYnChecked == true) {
    ds_vlFixCost.setCellData(fRow, "divsYn", "1");
    let levyAmtVal = Number(ds_vlFixCost.getCellData(fRow, "levyAmt"));
    let divsCnt = 0;
    let levyDdVal = ds_vlFixCost.getCellData(fRow, "levyDd");
    let divsAmtVal = 0;
    let levyStDdVal = ds_vlFixCost.getCellData(fRow, "levyStDd").trim();
    let levyStY = Number(levyStDdVal.substring(0, 4));
    let levyStM = Number(levyStDdVal.substring(4, 6));
    let levyStD = Number(levyStDdVal.substring(6, 8));
    let levyEndDdVal = ds_vlFixCost.getCellData(fRow, "levyEndDd").trim();
    let levyEndY = Number(levyEndDdVal.substring(0, 4));
    let levyEndM = Number(levyEndDdVal.substring(4, 6));
    let levyEndD = Number(levyEndDdVal.substring(6, 8));
    divsCnt = (levyEndY - levyStY) * 12;
    divsCnt += levyEndM - levyStM - 1;
    if (levyStD < Number(levyDdVal)) {
      divsCnt++;
    }
    if (levyEndD > Number(levyDdVal)) {
      divsCnt++;
    }
    if (divsCnt > 0) {
      divsAmtVal = levyAmtVal / divsCnt;
    }
    ds_vlFixCost.setCellData(fRow, "divsAmt", String(divsAmtVal));
  } else {
    ds_vlFixCost.setCellData(fRow, "divsYn", "0");
    ds_vlFixCost.setCellData(fRow, "divsAmt", "");
  }
};
scwin.calcDivsIns = function () {
  let iRow = ds_vlInsurance.getRowPosition();
  let divsYnChecked = ds_vlInsurance.getCellData(iRow, "divsYn");
  if (divsYnChecked == "1" || divsYnChecked == true) {
    ds_vlInsurance.setCellData(iRow, "divsYn", "1");
    let inpayMm = 0;
    let entryDateVal = ds_vlInsurance.getCellData(iRow, "entryDate").trim();
    let levyStY = Number(entryDateVal.substring(0, 4));
    let levyStM = Number(entryDateVal.substring(4, 6));
    let insrDueDateVal = ds_vlInsurance.getCellData(iRow, "insrDueDate").trim();
    let levyEndY = Number(insrDueDateVal.substring(0, 4));
    let levyEndM = Number(insrDueDateVal.substring(4, 6));
    inpayMm = (levyEndY - levyStY) * 12;
    inpayMm += levyEndM - levyStM - 1;
    ds_vlInsurance.setCellData(iRow, "inpayMm", String(inpayMm));
  } else {
    ds_vlInsurance.setCellData(iRow, "divsYn", "0");
    ds_vlInsurance.setCellData(iRow, "inpayMm", "");
  }
};
