scwin.chkVehclNo = async function () {
  let vno = vehclNo.getValue().trim();
  let vnoLen = vno.length;
  let vno4 = vno.substring(vnoLen - 4, vnoLen);
  let num = "0123456789";
  for (let i = 0; i < 4; i++) {
    if (num.indexOf(vno4.substring(i, i + 1)) < 0 || vnoLen > 9) {
      await $c.win.alert($p, "잘못된 차량번호 입니다.");
      vehclNo.setFocus();
      return false;
    }
  }
  if (vehclNo.getValue() != "") {
    ds_cond.removeAll();
    ds_cond.insertRow();
    let cRow = ds_cond.getRowPosition();
    ds_cond.setCellData(cRow, "cond1", "1");
    ds_cond.setCellData(cRow, "cond2", vehclNo.getValue());
    ds_cond.setCellData(cRow, "all", "0");
    await $c.sbm.execute($p, sbm_chkVehclNo);
  }
};
