scwin.f_Download = async function () {
  let row = ds_vehcl.getRowPosition();
  let fileName = ds_vehcl.getCellData(row, "filenm");
  let filePath = ds_vehcl.getCellData(row, "filepath");
  if (filePath.trim().length == 0) {
    await $c.win.alert($p, "첨부파일이 없습니다.");
  } else {
    if (filePath.indexOf(".") > 0) {
      fileName += filePath.substring(filePath.indexOf("."), filePath.indexOf(".") + 4);
      $c.gus.cfDownloadFile($p, fileName, filePath);
    }
  }
};
